package com.duybao.SplitGo.Enum;

public enum AddressType {
    HOME,
    OFFICE,
    OTHER
}

package com.duybao.SplitGo.Enum;

public enum SellerVerificationStatus {
    PENDING,
    APPROVED,
    REJECTED
}

package com.duybao.SplitGo.Enum;

public enum ShippingStatus {
    PENDING,
    IN_TRANSIT,
    OUT_FOR_DELIVERY,
    DELIVERED,
    FAILED
}

package com.duybao.SplitGo.Enum;

public enum StoreStatus {
    ACTIVE,
    SUSPENDED
